// The header of a heap chunk is 0x10 bytes in size
#define HEADER_SIZE 0x10

// This is the `tcache_perthread_struct` (or the tcache metadata)
struct tcache_metadata {
  char counts[TCACHE_BINS];
  void *entries[TCACHE_BINS];
};

