	printf("p2=%p.\n", p2);

	printf("\nFirst, malloc_consolidate will merge the fast chunk p1 with top.\n");
	printf("Then, p2 is allocated from top since there is no free chunk bigger (or equal) than it. Thus, p1 = p2.\n");

	assert(p1 == p2);

